// review-item.js
// A Playwright script to scrape detailed info from a specific Hacker News item
// URL: https://news.ycombinator.com/item?id=47699181

const { chromium } = require('playwright');

(async () => {
  const browser = await chromium.launch({ headless: true });
  const page = await browser.newPage();

  const url = 'https://news.ycombinator.com/item?id=47699181';
  console.log('Navigating to', url);
  await page.goto(url, { waitUntil: 'domcontentloaded' });

  // Extract the main post information
  const post = await page.evaluate(() => {
    const titleEl = document.querySelector('.title > a');
    const subtext = document.querySelector('.subtext');
    const title = titleEl ? titleEl.innerText : null;
    const link = titleEl ? titleEl.href : null;
    const pointsEl = subtext ? subtext.querySelector('span.score') : null;
    const points = pointsEl ? pointsEl.innerText : null;
    const authorEl = subtext ? subtext.querySelector('a.hnuser') : null;
    const author = authorEl ? authorEl.innerText : null;
    const timeEl = subtext ? subtext.querySelector('span.age') : null;
    const time = timeEl ? timeEl.innerText : null;
    const commentsEl = subtext ? subtext.querySelectorAll('a')[subtext.querySelectorAll('a').length - 1] : null;
    const commentsText = commentsEl ? commentsEl.innerText : null;
    const commentsCount = commentsText ? parseInt(commentsText) : null;
    return { title, link, points, author, time, commentsCount };
  });

  console.log('Post Info:', post);

  // Extract the top-level comments (first 5)
  const comments = await page.evaluate(() => {
    const rows = Array.from(document.querySelectorAll('tr.comtr'));
    const commentData = [];
    for (let i = 0; i < rows.length && commentData.length < 5; i++) {
      const row = rows[i];
      const authorEl = row.querySelector('a.hnuser');
      const textEl = row.querySelector('div.comment > span');
      const ageEl = row.querySelector('span.age');
      if (authorEl && textEl && ageEl) {
        commentData.push({
          author: authorEl.innerText,
          age: ageEl.innerText,
          text: textEl.innerText,
        });
      }
    }
    return commentData;
  });

  console.log('Top 5 Comments:', comments);

  await browser.close();
})();

