**Scraper – `review-item.js`**

```js
// review-item.js
// A Playwright script that pulls a full “review” of a Hacker‑News item
// and prints the post meta‑data plus the first five comments.

const { chromium } = require('playwright');

(async () => {
  // ① Start a headless browser
  const browser = await chromium.launch({ headless: true });
  const page = await browser.newPage();

  const url = 'https://news.ycombinator.com/item?id=47699181';
  console.log('Navigating to', url);
  await page.goto(url, { waitUntil: 'domcontentloaded' });

  // ② Pull post meta‑data (title, link, points, author, age, comment count)
  const post = await page.evaluate(() => {
    // Main post row (the first .athing on the page)
    const titleEl = document.querySelector('.athing .titleline > a');
    const link = titleEl ? titleEl.getAttribute('href') : null;
    const title = titleEl ? titleEl.innerText : null;

    const subtext = document.querySelector('.athing .subtext');
    const pointsEl = subtext?.querySelector('span.score');
    const points = pointsEl ? pointsEl.innerText : null;

    const authorEl = subtext?.querySelector('a.hnuser');
    const author = authorEl ? authorEl.innerText : null;

    const timeEl = subtext?.querySelector('a.age');
    const time = timeEl ? timeEl.innerText : null;

    const commentsLink = subtext?.querySelectorAll('a')?.slice(-1)[0];
    const commentsCount = commentsLink
      ? parseInt(commentsLink.innerText.replace(/\D/g, ''))
      : 0;

    return { title, link, points, author, time, commentsCount };
  });

  console.log('Post Info:', post);

  // ③ Pull the first 5 comments
  const comments = await page.evaluate(() => {
    const rows = Array.from(document.querySelectorAll('tr.comtr'));
    const commentData = [];

    for (const row of rows) {
      if (commentData.length >= 5) break;

      const authorEl = row.querySelector('a.hnuser');
      const ageEl   = row.querySelector('a.age');
      const textEl  = row.querySelector('div.comment > div.commtext');

      if (!authorEl || !ageEl || !textEl) continue;

      commentData.push({
        author: authorEl.innerText,
        age: ageEl.innerText,
        text: textEl.innerText.trim(),
      });
    }
    return commentData;
  });

  console.log('Top 5 Comments:', comments);

  await browser.close();
})();
```

### What the script does

| Step | Action |
|------|--------|
| 1 | Launches Chromium headless |
| 2 | Navigates to the specific item page |
| 3 | Extracts the post title, link, score, author, age and comment count |
| 4 | Gathers the first five comments (author, age, text) |
| 5 | Prints the collected data and exits |

