// follow-commenters.js
// Scrapes the item page, extracts the first 5 comments, then follows each commenter's
// Hacker‑News profile page to collect basic metadata.

const { chromium } = require('playwright');

(async () => {
  const browser = await chromium.launch({ headless: true });
  const page = await browser.newPage();

  const itemUrl = 'https://news.ycombinator.com/item?id=47699181';
  console.log('Navigating to', itemUrl);
  await page.goto(itemUrl, { waitUntil: 'domcontentloaded' });

  // Extract first 5 comments
  const comments = await page.evaluate(() => {
    const rows = Array.from(document.querySelectorAll('tr.comtr'));
    const commentData = [];
    for (const row of rows) {
      if (commentData.length >= 5) break;
      const authorEl = row.querySelector('a.hnuser');
      const ageEl   = row.querySelector('a.age');
      const textEl  = row.querySelector('div.comment > div.commtext');
      if (!authorEl || !ageEl || !textEl) continue;
      commentData.push({
        author: authorEl.innerText,
        age: ageEl.innerText,
        text: textEl.innerText.trim(),
      });
    }
    return commentData;
  });

  console.log('Top 5 Comments:', comments);

  const uniqueAuthors = [...new Set(comments.map(c => c.author))];
  const users = [];

  for (const username of uniqueAuthors) {
    const userUrl = `https://news.ycombinator.com/user?id=${username}`;
    const userPage = await browser.newPage();
    await userPage.goto(userUrl, { waitUntil: 'domcontentloaded' });
    const data = await userPage.evaluate(() => {
      const getText = sel => {
        const el = document.querySelector(sel);
        return el ? el.innerText.trim() : null;
      };
      return {
        username: getText('a.hnuser') || getText('td a'),
        created: getText('td:contains("created:") + td .age') || getText('td:contains("created:") + td'),
        karma: getText('td:contains("karma:") + td'),
        about: getText('td:contains("about:") + td') || '',
      };
    });
    users.push(data);
    await userPage.close();
  }

  console.log('User Profiles:');
  users.forEach(u => console.log(u));

  await browser.close();
})();

