// follow-commenters.js
// Scrapes the item page, extracts the first 5 comments, then follows each commenter's
// Hacker‑News profile page to collect basic metadata.

const { chromium } = require('playwright');

(async () => {
  const browser = await chromium.launch({ headless: true });
  const page = await browser.newPage();

  const itemUrl = 'https://news.ycombinator.com/item?id=47699181';
  console.log('Navigating to', itemUrl);
  await page.goto(itemUrl, { waitUntil: 'networkidle' });
const pageHTML = await page.content();
console.log('Page HTML length:', pageHTML.length);

  // Extract first 5 comments
  const commentCount = await page.evaluate(() => document.querySelectorAll('tr.comtr').length);
console.log('commentCount from evaluate:', commentCount);
const comments = await page.evaluate(() => { console.log('eval running'); console.log('rows count', document.querySelectorAll('tr.comtr').length);
    const rows = Array.from(document.querySelectorAll('tr.comtr'));
    const commentData = [];
    for (const row of rows) {
      if (commentData.length >= 5) break;
      const authorEl = row.querySelector('a.hnuser');
      const ageEl   = row.querySelector('a.age');
      const textEl  = row.querySelector('div.comment > div.commtext');
      if (!authorEl || !ageEl || !textEl) continue;
      commentData.push({
        author: authorEl.innerText,
        age: ageEl.innerText,
        text: textEl.innerText.trim(),
      });
    }
    return commentData;
  });

  console.log('Top 5 Comments:', comments);
console.log('Comment count:', comments.length);

  const uniqueAuthors = [...new Set(comments.map(c => c.author))];
  const users = [];

  for (const username of uniqueAuthors) {
    const userUrl = `https://news.ycombinator.com/user?id=${username}`;
    const userPage = await browser.newPage();
    await userPage.goto(userUrl, { waitUntil: 'networkidle' });
    const data = await userPage.evaluate(() => {
      const rows = Array.from(document.querySelectorAll('tr'));
      const info = {};
      rows.forEach(row => {
        const keyTd = row.children[0];
        const valTd = row.children[1];
        if (!keyTd || !valTd) return;
        const key = keyTd.textContent.trim();
        const val = valTd.textContent.trim();
        if (key.includes('user')) {
          info.username = valTd.querySelector('a')?.textContent.trim() || val;
        } else if (key.includes('created')) {
          info.created = valTd.querySelector('.age')?.textContent.trim() || val;
        } else if (key.includes('karma')) {
          info.karma = val;
        } else if (key.includes('about')) {
          info.about = val;
        }
      });
      return info;
    });
    users.push(data);
    await userPage.close();
  }

  console.log('User Profiles:');
  users.forEach(u => console.log(u));

  await browser.close();
})();

