// full-comments.js
// Scrape all comments from a Hacker‑News item and the profile data for each commenter.
// Uses only Playwright – no external HTTP libraries.

const { chromium } = require('playwright');

(async () => {
  const browser = await chromium.launch({ headless: true });
  const page = await browser.newPage();

  const itemUrl = 'https://news.ycombinator.com/item?id=47699181';
  console.log('Navigating to', itemUrl);
  await page.goto(itemUrl, { waitUntil: 'networkidle', timeout: 0 });

  // Extract all comments
  const comments = await page.evaluate(() => {
    const rows = Array.from(document.querySelectorAll('tr.comtr'));
    const data = [];
    for (const row of rows) {
      const id = row.id; // comment id
      const authorEl = row.querySelector('a.hnuser');
      const ageEl = row.querySelector('.age');
      const textEl = row.querySelector('.commtext');
      if (!authorEl || !ageEl || !textEl) continue;
      data.push({
        id,
        author: authorEl.innerText.trim(),
        age: ageEl.innerText.trim(),
        text: textEl.innerText.trim(),
      });
    }
    return data;
  });

  console.log(`Found ${comments.length} comments`);
  console.log('First 3 comments:');
  console.dir(comments.slice(0, 3), { depth: null });

  const uniqueAuthors = [...new Set(comments.map(c => c.author))];
  console.log(`Unique commenters: ${uniqueAuthors.length}`);

  const users = [];
  for (const username of uniqueAuthors) {
    const userUrl = `https://news.ycombinator.com/user?id=${username}`;
    const userPage = await browser.newPage();
    await userPage.goto(userUrl, { waitUntil: 'networkidle', timeout: 0 });
    const data = await userPage.evaluate(() => {
      const rows = Array.from(document.querySelectorAll('tr'));
      const info = {};
      for (const row of rows) {
        const keyTd = row.children[0];
        const valTd = row.children[1];
        if (!keyTd || !valTd) continue;
        const key = keyTd.textContent.trim();
        const val = valTd.textContent.trim();
        if (key.includes('user')) {
          info.username = valTd.querySelector('a')?.textContent.trim() || val;
        } else if (key.includes('created')) {
          info.created = valTd.querySelector('.age')?.textContent.trim() || val;
        } else if (key.includes('karma')) {
          info.karma = val;
        } else if (key.includes('about')) {
          info.about = val;
        }
      }
      return info;
    });
    users.push(data);
    await userPage.close();
  }

  console.log('User Profiles:');
  console.dir(users, { depth: null });

  await browser.close();
})();

